-- Slot Bookings (500 total)

-- Update slots aggregates based on confirmed bookings
UPDATE slots SET current_orders = (SELECT COUNT(*) FROM slot_bookings WHERE slot_bookings.slot_id = slots.id AND slot_bookings.status = 'confirmed');
UPDATE slots SET congestion_level = LEAST(1.0, current_orders::float / NULLIF(max_orders, 0));

